mapper.update:
update biz_social_match
status = #{status}, response_time = #{responseTime}, update_by = #{updateBy}, update_time = sysdate()
where match_id = #{matchId}

mapper.select:
select count(1)
from biz_social_friend
where pet_id = #{petId}
  and friend_pet_id = #{friendPetId}
  and status = '0'

select
    coalesce(sum(case when m.status = '2' then 1 else 0 end), 0) as successInteractionCount,
    coalesce(sum(case when m.status = '1' and m.receiver_user_id = #{userId} then 1 else 0 end), 0) as pendingReceivedCount,
    coalesce(sum(case when m.status = '1' and m.initiator_user_id = #{userId} then 1 else 0 end), 0) as pendingSentCount,
    (
        select count(1)
        from biz_social_friend f
        where f.user_id = #{userId}
          and f.status = '0'
    ) as friendCount,
    (
        coalesce(sum(case when m.status = '2' then 1 else 0 end), 0) * 10 +
        (
            select count(1)
            from biz_social_friend f
            where f.user_id = #{userId}
              and f.status = '0'
        ) * 20
    ) as socialActivityScore
from biz_social_match m
where m.initiator_user_id = #{userId}
   or m.receiver_user_id = #{userId}
